// src/components/EmpresaModal.js

import React from 'react';
import { motion } from 'framer-motion';

const EmpresaModal = ({ empresa, onClose }) => {
    if (!empresa) return null;

    // Usaremos AnimatePresence en el componente padre para controlar la entrada/salida.
    // Aquí solo necesitamos motion.
    return (
        <motion.div
            // El contenedor principal del modal, que lo fija en el lugar (z-10 para estar por encima de todo)
            className="absolute inset-0 bg-white rounded-lg p-6 shadow-xl flex flex-col items-center justify-center overflow-y-auto z-10" 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            transition={{ duration: 0.3 }}
        >
            {/* Botón de Cerrar */}
            <button
                onClick={onClose}
                className="absolute top-4 right-4 text-gray-500 hover:text-gray-800 transition-colors"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
            </button>
            
            {/* Contenido del Modal */}
            <div className="text-center mb-6">
                <h2 className="text-3xl font-bold text-gray-900">{empresa.nombre}</h2>
                <p className="text-lg text-gray-600">{empresa.rubro}</p>
                <p className="text-sm text-gray-500 italic">"{empresa.slogan}"</p>
            </div>
            
            <div className="w-full flex-shrink-0 mb-4 rounded-lg overflow-hidden">
                <img
                    src={empresa.imagen}
                    alt={`Logo de ${empresa.nombre}`}
                    className="w-full h-48 object-cover"
                />
            </div>
            
            <div className="w-full text-gray-700 text-center">
                <p className="text-base mb-2">{empresa.descripcion}</p>
                <p className="text-sm">
                    <span className="font-semibold">Departamento:</span> {empresa.departamento}
                </p>
            </div>
        </motion.div>
    );
};

export default EmpresaModal;
